// ui-cards.js — renders account cards to #accountsGrid and drives the TOTP tick loop.
// Mirrors the card HTML generated by TotpManager.Web's Razor template.
// Depends on: accounts.js, totp.js, otpauth.js, qr.js

var TotpSpa = window.TotpSpa || {};

TotpSpa.UiCards = (function () {
    'use strict';

    // ── HTML helpers ──────────────────────────────────────────────────────

    function esc(s) {
        return String(s == null ? '' : s)
            .replace(/&/g, '&amp;').replace(/</g, '&lt;')
            .replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    }

    // ── Card template ─────────────────────────────────────────────────────

    function makeCardHtml(account, idx) {
        const gearId   = `gear-${idx}`;
        const editId   = `edit-${idx}`;
        const isTotp   = account.typeLabel !== 'HOTP';
        const display  = esc(account.issuer || account.name);
        const subtext  = account.issuer && account.issuer !== account.name
            ? `<small class="text-muted">${esc(account.name)}</small>` : '';

        const totpHtml = isTotp ? `
            <div class="w-100 px-2 mt-1" data-otp-uri="${esc(account.uri)}">
                <div class="d-flex align-items-center justify-content-center gap-2">
                    <div class="font-monospace fw-bold totp-code"
                         style="font-size:2rem;letter-spacing:0.18em;line-height:1.1;">&middot;&middot;&middot;</div>
                    <button type="button" class="btn btn-sm btn-outline-success totp-copy"
                            onclick="TotpSpa.UiCards.copyTotp(this)" title="Copy code">&#128203;</button>
                </div>
                <div class="d-flex align-items-center gap-2 mt-1">
                    <div class="progress flex-grow-1" style="height:4px;">
                        <div class="progress-bar totp-bar" role="progressbar"
                             style="width:100%;transition:none;"></div>
                    </div>
                    <small class="text-muted totp-seconds" style="min-width:2.2em;text-align:right;">30s</small>
                </div>
            </div>` : '';

        return `
        <div class="col" data-search="${esc((account.issuer + ' ' + account.name).toLowerCase())}">
          <div class="card shadow-sm text-center">
            <div class="card-body d-flex flex-column align-items-center gap-2">
              <div class="fw-semibold mt-1">${display}</div>
              ${subtext}
              ${totpHtml}

              <!-- Action bar -->
              <div class="d-flex justify-content-center gap-2 mt-auto pt-2">
                <button type="button" class="btn btn-sm btn-outline-secondary"
                        onclick="TotpSpa.UiCards.toggleGear('${gearId}','${editId}','${esc(account.uri)}')"
                        title="Details">&#9881;</button>
                <button type="button" class="btn btn-sm btn-outline-primary"
                        onclick="TotpSpa.UiCards.toggleEdit('${gearId}','${editId}')"
                        title="Edit">&#9998;</button>
                <button type="button" class="btn btn-sm btn-outline-danger"
                        onclick="TotpSpa.UiCards.confirmDelete('${esc(account.uri)}')"
                        title="Delete">&#128465;</button>
              </div>

              <!-- Gear panel (details + QR) -->
              <div id="${gearId}" style="display:none" class="border-top pt-2 text-center w-100">
                <img class="qr-img img-fluid border rounded mb-2"
                     style="max-width:160px;min-width:160px;min-height:160px;background:#f8f9fa;"
                     src="" alt="QR code" />
                <small class="text-muted d-block mb-2">
                    ${esc(account.typeLabel)} &middot; ${esc(account.algLabel)} &middot; ${account.digits} digits
                </small>
                <div class="d-flex justify-content-center gap-2">
                  <button type="button" class="btn btn-sm btn-outline-primary"
                          data-uri="${esc(account.uri)}"
                          onclick="navigator.clipboard.writeText(this.dataset.uri)">
                      &#128203; Copy URI
                  </button>
                  <a href="#" class="btn btn-sm btn-outline-secondary qr-download"
                     download="${esc((account.issuer || account.name) + '.png')}">&#8659; PNG</a>
                </div>
              </div>

              <!-- Edit panel -->
              <div id="${editId}" style="display:none" class="border-top pt-2 text-start w-100">
                <div class="mb-2">
                  <label class="form-label small mb-1">Service</label>
                  <input type="text" class="form-control form-control-sm edit-issuer"
                         value="${esc(account.issuer)}" />
                </div>
                <div class="mb-2">
                  <label class="form-label small mb-1">Account</label>
                  <input type="text" class="form-control form-control-sm edit-name"
                         value="${esc(account.name)}" />
                </div>
                <div class="d-flex gap-2">
                  <button type="button" class="btn btn-sm btn-primary"
                          onclick="TotpSpa.UiCards.saveEdit('${editId}','${esc(account.uri)}')">Save</button>
                  <button type="button" class="btn btn-sm btn-outline-secondary"
                          onclick="TotpSpa.UiCards.toggleEdit('${gearId}','${editId}')">Cancel</button>
                </div>
              </div>

            </div>
          </div>
        </div>`;
    }

    // ── Render ────────────────────────────────────────────────────────────

    function render() {
        const accounts = TotpSpa.Accounts.getAll();
        const grid     = document.getElementById('accountsGrid');
        if (!grid) return;

        // Sort: issuer ASC then name ASC (case-insensitive) — matches C# LINQ order
        const sorted = [...accounts].sort((a, b) => {
            const ic = (a.issuer || '').localeCompare(b.issuer || '', undefined, { sensitivity: 'base' });
            return ic !== 0 ? ic : (a.name || '').localeCompare(b.name || '', undefined, { sensitivity: 'base' });
        });

        grid.innerHTML = sorted.map((a, i) => makeCardHtml(a, i)).join('');
        _updateToolbar(accounts.length);
    }

    function _updateToolbar(count) {
        const search = document.getElementById('searchInput');
        const cnt    = document.getElementById('accountCount');
        const backup = document.getElementById('backupBtn');
        if (search) search.style.display = count > 0 ? '' : 'none';
        if (cnt)    { cnt.style.display = count > 0 ? '' : 'none'; cnt.innerHTML = `<strong>${count}</strong> account(s)`; }
        if (backup) backup.disabled = count === 0;
    }

    // ── Panel toggles ─────────────────────────────────────────────────────

    function toggleGear(gearId, editId, uri) {
        const gear = document.getElementById(gearId);
        const edit = document.getElementById(editId);
        const willOpen = gear.style.display === 'none';
        edit.style.display = 'none';
        gear.style.display = willOpen ? '' : 'none';

        // Lazy QR generation — only when panel opens for the first time.
        // Must use getAttribute('src') not img.src — browsers resolve src=""
        // to the page URL, making img.src always truthy even when unset.
        if (willOpen) {
            const img    = gear.querySelector('.qr-img');
            const dlLink = gear.querySelector('.qr-download');
            if (img && img.getAttribute('src') === '') {
                TotpSpa.QR.generateDataUrl(uri).then(dataUrl => {
                    img.src = dataUrl;
                    if (dlLink) dlLink.href = dataUrl;
                }).catch(() => {
                    if (img) img.alt = 'QR generation failed';
                });
            }
        }
    }

    function toggleEdit(gearId, editId) {
        const gear     = document.getElementById(gearId);
        const edit     = document.getElementById(editId);
        const willOpen = edit.style.display === 'none';
        gear.style.display = 'none';
        edit.style.display = willOpen ? '' : 'none';
    }

    function confirmDelete(uri) {
        if (!confirm('Delete this account?')) return;
        TotpSpa.Accounts.deleteOne(uri);
    }

    function saveEdit(editId, oldUri) {
        const panel     = document.getElementById(editId);
        const newIssuer = panel.querySelector('.edit-issuer').value.trim();
        const newName   = panel.querySelector('.edit-name').value.trim();
        TotpSpa.Accounts.editOne(oldUri, newName, newIssuer);
    }

    // ── Search filter ─────────────────────────────────────────────────────

    function filterCards(query) {
        const q = (query || '').toLowerCase().trim();
        let visible = 0;
        document.querySelectorAll('#accountsGrid .col[data-search]').forEach(col => {
            const match = !q || col.dataset.search.includes(q);
            col.style.display = match ? '' : 'none';
            if (match) visible++;
        });
        const total  = document.querySelectorAll('#accountsGrid .col[data-search]').length;
        const cntEl  = document.getElementById('accountCount');
        if (cntEl) {
            cntEl.innerHTML = q
                ? `<strong>${visible}</strong> of <strong>${total}</strong> account(s)`
                : `<strong>${total}</strong> account(s)`;
        }
    }

    // ── TOTP tick ─────────────────────────────────────────────────────────

    async function _tick() {
        const now = Math.floor(Date.now() / 1000);
        for (const el of document.querySelectorAll('[data-otp-uri]')) {
            const params = TotpSpa.OtpAuth.parseOtpUri(el.dataset.otpUri);
            if (!params) continue;
            const remaining = params.period - (now % params.period);
            const pct       = (remaining / params.period) * 100;
            const barCls    = remaining <= 5  ? 'progress-bar bg-danger totp-bar'
                            : remaining <= 10 ? 'progress-bar bg-warning totp-bar'
                            :                   'progress-bar totp-bar';
            el.querySelector('.totp-bar').className    = barCls;
            el.querySelector('.totp-bar').style.width  = pct + '%';
            el.querySelector('.totp-seconds').textContent = remaining + 's';
            try {
                const code = await TotpSpa.Totp.generate(params);
                el.querySelector('.totp-code').textContent = TotpSpa.Totp.groupCode(code);
            } catch {
                el.querySelector('.totp-code').textContent = 'error';
            }
        }
    }

    function startTick() {
        _tick();
        setInterval(_tick, 1000);
    }

    function copyTotp(btn) {
        const code = btn.closest('[data-otp-uri]')
            .querySelector('.totp-code')
            .textContent.replace(/\s/g, '');
        navigator.clipboard.writeText(code).then(() => {
            const orig = btn.innerHTML;
            btn.innerHTML = '&#10003;';
            btn.disabled  = true;
            setTimeout(() => { btn.innerHTML = orig; btn.disabled = false; }, 1500);
        });
    }

    return { render, toggleGear, toggleEdit, confirmDelete, saveEdit, filterCards, startTick, copyTotp };
})();
